#include<bits/stdc++.h>
using namespace std;
#define MAXN 5010
vector<int> p[MAXN];
int ind[MAXN],n,outd[MAXN],m,ans,f[MAXN];
queue<int> q;
int main(void){
	cin>>n>>m;
	for(int i=1;i<=m;i++){int x,y;cin>>x>>y,ind[y]++,outd[x]++,p[x].push_back(y);}
	memset(f,0,sizeof(f));
	for(int i=1;i<=n;i++)if(ind[i]==0)q.push(i),f[i]=1;
	while(!q.empty()){
		int x=q.front();
		q.pop();
		for(int i=0;i<p[x].size();i++){
			int y=p[x][i];f[y]=(f[x]+f[y])%80112002;ind[y]--;
			if(ind[y]==0)q.push(y);
		}
	}
	for(int i=1;i<=n;i++)if(outd[i]==0)ans=(ans+f[i])%80112002;
	cout<<ans;
	return false;
}
